        this(UniffiWithHandle, 
    uniffiRustCall() { _status ->
    UniffiLib.uniffi_slatedb_uniffi_fn_constructor_adminbuilder_new(
    
        FfiConverterString.lower(`path`),FfiConverterTypeObjectStore.lower(`objectStore`),_status)
