/**
 * Read-only snapshot representing a consistent view of the database.
 */
public interface DbSnapshotInterface {
    
    /**
     * Reads the value visible in this snapshot for `key`.
     */
    suspend fun `get`(`key`: kotlin.ByteArray): kotlin.ByteArray?
    
    /**
     * Reads the row version visible in this snapshot for `key`.
     */
    suspend fun `getKeyValue`(`key`: kotlin.ByteArray): KeyValue?
    
    /**
     * Reads the row version visible in this snapshot for `key` using custom read options.
     */
    suspend fun `getKeyValueWithOptions`(`key`: kotlin.ByteArray, `options`: ReadOptions): KeyValue?
    
    /**
     * Reads the value visible in this snapshot for `key` using custom read options.
     */
    suspend fun `getWithOptions`(`key`: kotlin.ByteArray, `options`: ReadOptions): kotlin.ByteArray?
    
    /**
     * Scans rows inside `range` as of this snapshot.
     */
    suspend fun `scan`(`range`: KeyRange): DbIterator
    
    /**
     * Scans rows whose keys start with `prefix` as of this snapshot,
     * restricted to `subrange`.
     */
    suspend fun `scanPrefix`(`prefix`: kotlin.ByteArray, `subrange`: KeyRange): DbIterator
    
    /**
     * Scans rows whose keys start with `prefix` as of this snapshot,
     * restricted to `subrange`, using custom options.
     */
    suspend fun `scanPrefixWithOptions`(`prefix`: kotlin.ByteArray, `subrange`: KeyRange, `options`: ScanOptions): DbIterator
    
    /**
     * Scans rows inside `range` as of this snapshot using custom scan options.
     */
    suspend fun `scanWithOptions`(`range`: KeyRange, `options`: ScanOptions): DbIterator
    
    companion object
}

