    fun `registerCounter`(`name`: kotlin.String, `description`: kotlin.String?, `labels`: List<MetricLabel>): Counter
    
    fun `registerGauge`(`name`: kotlin.String, `description`: kotlin.String?, `labels`: List<MetricLabel>): Gauge
    
