    /**
     * Registers an up/down counter.
     */
    fun `registerUpDownCounter`(`name`: kotlin.String, `description`: kotlin.String?, `labels`: List<MetricLabel>): UpDownCounter
    
    /**
     * Registers a histogram with explicit bucket boundaries.
     */
    fun `registerHistogram`(`name`: kotlin.String, `description`: kotlin.String?, `labels`: List<MetricLabel>, `boundaries`: List<kotlin.Double>): Histogram
    
    companion object
}

