/**
 * Cache content that [`crate::Db::warm_sst`] should populate.
 */
sealed class CacheTarget {
    
    /**
     * Warm all filters on the SST, if any exist.
     */
    object Filters : CacheTarget()
    
    
    /**
     * Warm the SST index.
     */
    object Index : CacheTarget()
    
    
    /**
     * Warm the SST stats block, if one exists.
     */
    object Stats : CacheTarget()
    
    
    /**
     * Warm the SST data blocks that overlap `range`. Also warms the index,
     * since block planning depends on it.
     */
    data class Data(
        val `range`: uniffi.slatedb.KeyRange) : CacheTarget()
        
    {
        

        companion object
    }
    

    

    
    


    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeCacheTarget : FfiConverterRustBuffer<CacheTarget>{
    override fun read(buf: ByteBuffer): CacheTarget {
        return when(buf.getInt()) {
            1 -> CacheTarget.Filters
            2 -> CacheTarget.Index
            3 -> CacheTarget.Stats
            4 -> CacheTarget.Data(
                FfiConverterTypeKeyRange.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: CacheTarget) = when(value) {
        is CacheTarget.Filters -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is CacheTarget.Index -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is CacheTarget.Stats -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is CacheTarget.Data -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterTypeKeyRange.allocationSize(value.`range`)
            )
        }
    }

    override fun write(value: CacheTarget, buf: ByteBuffer) {
        when(value) {
            is CacheTarget.Filters -> {
                buf.putInt(1)
                Unit
            }
            is CacheTarget.Index -> {
                buf.putInt(2)
                Unit
            }
