/**
 * Error type returned by the UniFFI bindings.
 */
sealed class Exception: kotlin.Exception() {
    
    /**
     * Transaction-specific failure.
     */
    class Transaction(
        
        override val `message`: kotlin.String
        ) : Exception() {
    }
    
    /**
     * Operation attempted on a closed handle.
     */
    class Closed(
        
        /**
         * Reported reason the handle is closed.
         */
        val `reason`: CloseReason, 
        
        /**
         * Human-readable error message.
         */
        override val `message`: kotlin.String
        ) : Exception() {
    }
    
    /**
     * Temporary unavailability, such as an unavailable dependency.
     */
    class Unavailable(
        
        override val `message`: kotlin.String
        ) : Exception() {
    }
    
    /**
     * Invalid input or invalid API usage.
     */
    class Invalid(
        
        override val `message`: kotlin.String
        ) : Exception() {
    }
    
    /**
     * Corrupt, missing, or otherwise invalid data was encountered.
     */
    class Data(
        
        override val `message`: kotlin.String
        ) : Exception() {
    }
    
    /**
     * Internal failure inside SlateDB or the binding layer.
     */
    class Internal(
        
        override val `message`: kotlin.String
        ) : Exception() {
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<Exception> {
        override fun lift(error_buf: RustBuffer.ByValue): Exception = FfiConverterTypeError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeError : FfiConverterRustBuffer<Exception> {
    override fun read(buf: ByteBuffer): Exception {
        

        return when(buf.getInt()) {
            1 -> Exception.Transaction(
                FfiConverterString.read(buf),
                )
            2 -> Exception.Closed(
                FfiConverterTypeCloseReason.read(buf),
                FfiConverterString.read(buf),
                )
            3 -> Exception.Unavailable(
                FfiConverterString.read(buf),
                )
            4 -> Exception.Invalid(
                FfiConverterString.read(buf),
                )
            5 -> Exception.Data(
                FfiConverterString.read(buf),
                )
            6 -> Exception.Internal(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: Exception): ULong {
        return when(value) {
            is Exception.Transaction -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is Exception.Closed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterTypeCloseReason.allocationSize(value.`reason`)
                + FfiConverterString.allocationSize(value.`message`)
            )
            is Exception.Unavailable -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is Exception.Invalid -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is Exception.Data -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is Exception.Internal -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
        }
    }

    override fun write(value: Exception, buf: ByteBuffer) {
        when(value) {
            is Exception.Transaction -> {
                buf.putInt(1)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is Exception.Closed -> {
                buf.putInt(2)
                FfiConverterTypeCloseReason.write(value.`reason`, buf)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is Exception.Unavailable -> {
                buf.putInt(3)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is Exception.Invalid -> {
                buf.putInt(4)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is Exception.Data -> {
                buf.putInt(5)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is Exception.Internal -> {
                buf.putInt(6)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



