/**
 * Time-to-live policy applied to an inserted value or merge operand.
 */
sealed class Ttl {
    
    /**
     * Use the database default TTL.
     */
    object Default : Ttl()
    
    
    /**
     * Store the value without expiration.
     */
    object NoExpiry : Ttl()
    
    
    /**
     * Expire the value after the given number of clock ticks.
     */
    data class ExpireAfterTicks(
        val v1: kotlin.ULong) : Ttl()
        
    {
        

        companion object
    }
    
    /**
     * Expire the value at the given absolute timestamp (clock ticks).
     */
    data class ExpireAt(
        val v1: kotlin.Long) : Ttl()
        
    {
        

        companion object
    }
    

    

    
    


    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeTtl : FfiConverterRustBuffer<Ttl>{
    override fun read(buf: ByteBuffer): Ttl {
        return when(buf.getInt()) {
            1 -> Ttl.Default
            2 -> Ttl.NoExpiry
            3 -> Ttl.ExpireAfterTicks(
                FfiConverterULong.read(buf),
                )
            4 -> Ttl.ExpireAt(
                FfiConverterLong.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: Ttl) = when(value) {
        is Ttl.Default -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is Ttl.NoExpiry -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is Ttl.ExpireAfterTicks -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterULong.allocationSize(value.v1)
            )
        }
        is Ttl.ExpireAt -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterLong.allocationSize(value.v1)
            )
        }
    }

    override fun write(value: Ttl, buf: ByteBuffer) {
        when(value) {
            is Ttl.Default -> {
                buf.putInt(1)
                Unit
            }
            is Ttl.NoExpiry -> {
                buf.putInt(2)
                Unit
            }
            is Ttl.ExpireAfterTicks -> {
                buf.putInt(3)
                FfiConverterULong.write(value.v1, buf)
                Unit
            }
            is Ttl.ExpireAt -> {
                buf.putInt(4)
                FfiConverterLong.write(value.v1, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}






